#include<bits/stdc++.h>
using namespace std;
struct edge
{
    int to,val,nxt;
}e[2000010];
int head[2000010],tot=1,flag[5050][5050];
int n,m,s,t,d[2000010],now[2000010];
int dx[8]={1,1,2,2,-1,-1,-2,-2};
int dy[8]={2,-2,1,-1,2,-2,1,-1};
void add1(int u,int v,int w)
{
    e[++tot]=(edge){v,w,head[u]};
    head[u]=tot;
}
void add(int u,int v,int w)
{
    add1(u,v,w);
    add1(v,u,0);
}
bool bfs()
{
    for(int i=0;i<=t;i++)
    {
        d[i]=0;
    }
    d[s]=1;
    queue<int> q;
    q.push(s);
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        for(int i=head[t];i;i=e[i].nxt)
        {
            int v=e[i].to,val=e[i].val;
            if(d[v]==0&&val)
            {
                d[v]=d[t]+1;
                q.push(v);
                if(v==::t)
                {
                    return true;
                }
            }
        }
    }
    return false;
}
int dfs(int x,int flow)
{
    if(x==t||flow==0)
    {
        return flow;
    }
    int sum=0;
    for(int i=now[x];i;i=e[i].nxt)
    {
        now[x]=i;
        int v=e[i].to,val=e[i].val;
        if(d[v]==d[x]+1&&val)
        {
            int tmp=dfs(v,min(flow,val));
            e[i].val-=tmp;
            e[i^1].val+=tmp;
            sum+=tmp;
            flow-=tmp;
            if(flow==0)
            {
                break;
            }
        }
    }
    if(sum==0)
    {
        d[x]=0;
    }
    return sum;
}
int dinic()
{
    int ans=0;
    while(bfs())
    {
        for(int i=0;i<=t;i++)
        {
            now[i]=head[i];
        }
        ans+=dfs(s,2e9);
    }
    return ans;
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        flag[x][y]=1;
    }
    s=0;
    t=n*n+1;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            int now=(i-1)*n+j;
            if((i+j)%2==1&&!flag[i][j])
            {
                add(s,now,1);
                for(int k=0;k<8;k++)
                {
                    int p=i+dx[k],q=j+dy[k];
                    if(p>0&&p<=n&&q>0&&q<=n&&!flag[p][q])
                    {
                        add(now,(p-1)*n+q,1);
                    }
                }
            }
            else if((i+j)%2==0&&!flag[i][j])
            {
                add(now,t,1);
            }
        }
    }
    printf("%lld",n*n-m-dinic());
    return 0;
}
